+    let level_hvs: Vec<Vec<i8>> = (0..num_levels)
+        .map(|i| random_binary_hv(hd_dim, i as u64))
+        .collect();
+
+    // Position hypervectors for encoding positions
+    let pos_hvs: Vec<Vec<i8>> = (0..input_dim)
